import{o as s,c as n,d as a}from"./app.99e26a0f.js";const e='{"title":"概述","description":"","frontmatter":{"title":"概述"},"headers":[{"level":2,"title":"Kubernetes组件","slug":"kubernetes组件"},{"level":2,"title":"Kubernetes对象","slug":"kubernetes对象"}],"relativePath":"docs/cloud-native/kubernetes/README.md","lastUpdated":1646964393218}',t={},o=a('<h2 id="kubernetes组件"><a class="header-anchor" href="#kubernetes组件" aria-hidden="true">#</a> Kubernetes组件</h2><h2 id="kubernetes对象"><a class="header-anchor" href="#kubernetes对象" aria-hidden="true">#</a> Kubernetes对象</h2><p>在 Kubernetes 系统中，Kubernetes 对象是持久化的实体。 Kubernetes 使用这些实体去表示整个集群的状态。</p><p>几乎每个 Kubernetes 对象包含两个嵌套的对象字段，它们负责管理对象的配置： <code>spec</code>（规约）和 <code>status</code>（状态）</p><p><code>spec</code> 你必须在创建对象时设置其内容，描述你希望对象所具有的特征： 期望状态（Desired State）</p><p><code>status</code> 描述了对象的当前状态（Current State），它是由 Kubernetes 系统和组件设置并更新的</p><div class="language-yaml"><pre><code><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> apps/v1\n<span class="token key atrule">kind</span><span class="token punctuation">:</span> Deployment\n<span class="token key atrule">metadata</span><span class="token punctuation">:</span>\n  <span class="token key atrule">name</span><span class="token punctuation">:</span> nginx<span class="token punctuation">-</span>deployment\n<span class="token key atrule">spec</span><span class="token punctuation">:</span>\n  <span class="token key atrule">selector</span><span class="token punctuation">:</span>\n    <span class="token key atrule">matchLabels</span><span class="token punctuation">:</span>\n      <span class="token key atrule">app</span><span class="token punctuation">:</span> nginx\n  <span class="token key atrule">replicas</span><span class="token punctuation">:</span> <span class="token number">2</span> <span class="token comment"># tells deployment to run 2 pods matching the template</span>\n  <span class="token key atrule">template</span><span class="token punctuation">:</span>\n    <span class="token key atrule">metadata</span><span class="token punctuation">:</span>\n      <span class="token key atrule">labels</span><span class="token punctuation">:</span>\n        <span class="token key atrule">app</span><span class="token punctuation">:</span> nginx\n    <span class="token key atrule">spec</span><span class="token punctuation">:</span>\n      <span class="token key atrule">containers</span><span class="token punctuation">:</span>\n      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> nginx\n        <span class="token key atrule">image</span><span class="token punctuation">:</span> nginx<span class="token punctuation">:</span>1.14.2\n        <span class="token key atrule">ports</span><span class="token punctuation">:</span>\n        <span class="token punctuation">-</span> <span class="token key atrule">containerPort</span><span class="token punctuation">:</span> <span class="token number">80</span>\n</code></pre></div><p><strong>必需字段</strong></p><ul><li><p><code>apiVersion</code> 创建该对象所使用的 Kubernetes API 的版本</p></li><li><p><code>kind</code> 想要创建的对象的类别</p></li><li><p><code>metadata</code> 唯一性标识对象的一些数据，包括一个 name 字符串、UID 和可选的 namespace</p></li><li><p><code>spec</code> 你所期望的该对象的状态</p></li></ul><p><strong>查看所有api版本</strong></p><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@node1 ~<span class="token punctuation">]</span><span class="token comment"># kubectl api-versions</span>\nadmissionregistration.k8s.io/v1\napiextensions.k8s.io/v1\napiregistration.k8s.io/v1\napps/v1\nauthentication.k8s.io/v1\nauthorization.k8s.io/v1\nautoscaling/v1\nautoscaling/v2\nautoscaling/v2beta1\nautoscaling/v2beta2\nbatch/v1\nbatch/v1beta1\ncertificates.k8s.io/v1\ncoordination.k8s.io/v1\ndiscovery.k8s.io/v1\ndiscovery.k8s.io/v1beta1\nevents.k8s.io/v1\nevents.k8s.io/v1beta1\nflowcontrol.apiserver.k8s.io/v1beta1\nflowcontrol.apiserver.k8s.io/v1beta2\nnetworking.k8s.io/v1\nnode.k8s.io/v1\nnode.k8s.io/v1beta1\npolicy/v1\npolicy/v1beta1\nrbac.authorization.k8s.io/v1\nscheduling.k8s.io/v1\nstorage.k8s.io/v1\nstorage.k8s.io/v1beta1\nv1\n</code></pre></div><p><strong>查看所有api资源</strong></p><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@node1 ~<span class="token punctuation">]</span><span class="token comment"># kubectl api-resources</span>\nNAME                              SHORTNAMES   APIVERSION                             NAMESPACED   KIND\nbindings                                       v1                                     <span class="token boolean">true</span>         Binding\ncomponentstatuses                 cs           v1                                     <span class="token boolean">false</span>        ComponentStatus\nconfigmaps                        cm           v1                                     <span class="token boolean">true</span>         ConfigMap\nendpoints                         ep           v1                                     <span class="token boolean">true</span>         Endpoints\nevents                            ev           v1                                     <span class="token boolean">true</span>         Event\nlimitranges                       limits       v1                                     <span class="token boolean">true</span>         LimitRange\nnamespaces                        ns           v1                                     <span class="token boolean">false</span>        Namespace\nnodes                             no           v1                                     <span class="token boolean">false</span>        Node\npersistentvolumeclaims            pvc          v1                                     <span class="token boolean">true</span>         PersistentVolumeClaim\npersistentvolumes                 <span class="token function">pv</span>           v1                                     <span class="token boolean">false</span>        PersistentVolume\npods                              po           v1                                     <span class="token boolean">true</span>         Pod\npodtemplates                                   v1                                     <span class="token boolean">true</span>         PodTemplate\nreplicationcontrollers            rc           v1                                     <span class="token boolean">true</span>         ReplicationController\nresourcequotas                    <span class="token function">quota</span>        v1                                     <span class="token boolean">true</span>         ResourceQuota\nsecrets                                        v1                                     <span class="token boolean">true</span>         Secret\nserviceaccounts                   sa           v1                                     <span class="token boolean">true</span>         ServiceAccount\nservices                          svc          v1                                     <span class="token boolean">true</span>         Service\nmutatingwebhookconfigurations                  admissionregistration.k8s.io/v1        <span class="token boolean">false</span>        MutatingWebhookConfiguration\nvalidatingwebhookconfigurations                admissionregistration.k8s.io/v1        <span class="token boolean">false</span>        ValidatingWebhookConfiguration\ncustomresourcedefinitions         crd,crds     apiextensions.k8s.io/v1                <span class="token boolean">false</span>        CustomResourceDefinition\napiservices                                    apiregistration.k8s.io/v1              <span class="token boolean">false</span>        APIService\ncontrollerrevisions                            apps/v1                                <span class="token boolean">true</span>         ControllerRevision\ndaemonsets                        ds           apps/v1                                <span class="token boolean">true</span>         DaemonSet\ndeployments                       deploy       apps/v1                                <span class="token boolean">true</span>         Deployment\nreplicasets                       rs           apps/v1                                <span class="token boolean">true</span>         ReplicaSet\nstatefulsets                      sts          apps/v1                                <span class="token boolean">true</span>         StatefulSet\ntokenreviews                                   authentication.k8s.io/v1               <span class="token boolean">false</span>        TokenReview\nlocalsubjectaccessreviews                      authorization.k8s.io/v1                <span class="token boolean">true</span>         LocalSubjectAccessReview\nselfsubjectaccessreviews                       authorization.k8s.io/v1                <span class="token boolean">false</span>        SelfSubjectAccessReview\nselfsubjectrulesreviews                        authorization.k8s.io/v1                <span class="token boolean">false</span>        SelfSubjectRulesReview\nsubjectaccessreviews                           authorization.k8s.io/v1                <span class="token boolean">false</span>        SubjectAccessReview\nhorizontalpodautoscalers          hpa          autoscaling/v2                         <span class="token boolean">true</span>         HorizontalPodAutoscaler\ncronjobs                          cj           batch/v1                               <span class="token boolean">true</span>         CronJob\n<span class="token function">jobs</span>                                           batch/v1                               <span class="token boolean">true</span>         Job\ncertificatesigningrequests        csr          certificates.k8s.io/v1                 <span class="token boolean">false</span>        CertificateSigningRequest\nleases                                         coordination.k8s.io/v1                 <span class="token boolean">true</span>         Lease\nendpointslices                                 discovery.k8s.io/v1                    <span class="token boolean">true</span>         EndpointSlice\nevents                            ev           events.k8s.io/v1                       <span class="token boolean">true</span>         Event\nflowschemas                                    flowcontrol.apiserver.k8s.io/v1beta2   <span class="token boolean">false</span>        FlowSchema\nprioritylevelconfigurations                    flowcontrol.apiserver.k8s.io/v1beta2   <span class="token boolean">false</span>        PriorityLevelConfiguration\ningressclasses                                 networking.k8s.io/v1                   <span class="token boolean">false</span>        IngressClass\ningresses                         ing          networking.k8s.io/v1                   <span class="token boolean">true</span>         Ingress\nnetworkpolicies                   netpol       networking.k8s.io/v1                   <span class="token boolean">true</span>         NetworkPolicy\nruntimeclasses                                 node.k8s.io/v1                         <span class="token boolean">false</span>        RuntimeClass\npoddisruptionbudgets              pdb          policy/v1                              <span class="token boolean">true</span>         PodDisruptionBudget\npodsecuritypolicies               psp          policy/v1beta1                         <span class="token boolean">false</span>        PodSecurityPolicy\nclusterrolebindings                            rbac.authorization.k8s.io/v1           <span class="token boolean">false</span>        ClusterRoleBinding\nclusterroles                                   rbac.authorization.k8s.io/v1           <span class="token boolean">false</span>        ClusterRole\nrolebindings                                   rbac.authorization.k8s.io/v1           <span class="token boolean">true</span>         RoleBinding\nroles                                          rbac.authorization.k8s.io/v1           <span class="token boolean">true</span>         Role\npriorityclasses                   pc           scheduling.k8s.io/v1                   <span class="token boolean">false</span>        PriorityClass\ncsidrivers                                     storage.k8s.io/v1                      <span class="token boolean">false</span>        CSIDriver\ncsinodes                                       storage.k8s.io/v1                      <span class="token boolean">false</span>        CSINode\ncsistoragecapacities                           storage.k8s.io/v1beta1                 <span class="token boolean">true</span>         CSIStorageCapacity\nstorageclasses                    sc           storage.k8s.io/v1                      <span class="token boolean">false</span>        StorageClass\nvolumeattachments                              storage.k8s.io/v1                      <span class="token boolean">false</span>        VolumeAttachment\n</code></pre></div><p><strong>查看资源对象拥有的字段</strong></p><p><code>kubectl explain &lt;资源对象名&gt;</code></p><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@node1 ~<span class="token punctuation">]</span><span class="token comment"># kubectl explain pod</span>\nKIND:     Pod\nVERSION:  v1\n\nDESCRIPTION:\n     Pod is a collection of containers that can run on a host. This resource is\n     created by clients and scheduled onto hosts.\n\nFIELDS:\n   apiVersion\t<span class="token operator">&lt;</span>string<span class="token operator">&gt;</span>\n     APIVersion defines the versioned schema of this representation of an\n     object. Servers should convert recognized schemas to the latest internal\n     value, and may reject unrecognized values. More info:\n     https://git.k8s.io/community/contributors/devel/sig-architecture/api-conventions.md<span class="token comment">#resources</span>\n\n   kind\t<span class="token operator">&lt;</span>string<span class="token operator">&gt;</span>\n     Kind is a string value representing the REST resource this object\n     represents. Servers may infer this from the endpoint the client submits\n     requests to. Cannot be updated. In CamelCase. More info:\n     https://git.k8s.io/community/contributors/devel/sig-architecture/api-conventions.md<span class="token comment">#types-kinds</span>\n\n   metadata\t<span class="token operator">&lt;</span>Object<span class="token operator">&gt;</span>\n     Standard object&#39;s metadata. More info:\n     https://git.k8s.io/community/contributors/devel/sig-architecture/api-conventions.md<span class="token comment">#metadata</span>\n\n   spec\t<span class="token operator">&lt;</span>Object<span class="token operator">&gt;</span>\n     Specification of the desired behavior of the pod. More info:\n     https://git.k8s.io/community/contributors/devel/sig-architecture/api-conventions.md<span class="token comment">#spec-and-status</span>\n\n   status\t<span class="token operator">&lt;</span>Object<span class="token operator">&gt;</span>\n     Most recently observed status of the pod. This data may not be up to date.\n     Populated by the system. Read-only. More info:\n     https://git.k8s.io/community/contributors/devel/sig-architecture/api-conventions.md<span class="token comment">#spec-and-status</span>\n\n</code></pre></div><p>以上命令只会列出一级字段，一级字段可能还包含二级字段、三级字段。如果想列出所有字段，可以加上<code>--recursive</code></p><p><code>kubectl explain pod --recursive</code></p><p>查看具体字段</p><p><code>kubectl explain pod.kind</code></p><p><strong>查看已存在资源的详情</strong></p><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@node1 ~<span class="token punctuation">]</span><span class="token comment"># kubectl get ns kubeops -o yaml</span>\napiVersion: v1\nkind: Namespace\nmetadata:\n  creationTimestamp: <span class="token string">&quot;2022-02-22T09:07:23Z&quot;</span>\n  labels:\n    kubernetes.io/metadata.name: kubeops\n  name: kubeops\n  resourceVersion: <span class="token string">&quot;4121364&quot;</span>\n  uid: 4a38aee3-eb89-454b-a981-e731c3e8aadc\nspec:\n  finalizers:\n  - kubernetes\nstatus:\n  phase: Active\n</code></pre></div><p>使用 <code>raw</code> 方式查看</p><p><code>kubectl get --raw &#39;/api/v1/namespaces/kubeops&#39;</code></p><div class="language-json"><pre><code><span class="token punctuation">{</span><span class="token property">&quot;kind&quot;</span><span class="token operator">:</span><span class="token string">&quot;Namespace&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;apiVersion&quot;</span><span class="token operator">:</span><span class="token string">&quot;v1&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;metadata&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token property">&quot;name&quot;</span><span class="token operator">:</span><span class="token string">&quot;kubeops&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;uid&quot;</span><span class="token operator">:</span><span class="token string">&quot;4a38aee3-eb89-454b-a981-e731c3e8aadc&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;resourceVersion&quot;</span><span class="token operator">:</span><span class="token string">&quot;4121364&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;creationTimestamp&quot;</span><span class="token operator">:</span><span class="token string">&quot;2022-02-22T09:07:23Z&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;labels&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token property">&quot;kubernetes.io/metadata.name&quot;</span><span class="token operator">:</span><span class="token string">&quot;kubeops&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token property">&quot;managedFields&quot;</span><span class="token operator">:</span><span class="token punctuation">[</span><span class="token punctuation">{</span><span class="token property">&quot;manager&quot;</span><span class="token operator">:</span><span class="token string">&quot;kubectl-create&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;operation&quot;</span><span class="token operator">:</span><span class="token string">&quot;Update&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;apiVersion&quot;</span><span class="token operator">:</span><span class="token string">&quot;v1&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;time&quot;</span><span class="token operator">:</span><span class="token string">&quot;2022-02-22T09:07:23Z&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;fieldsType&quot;</span><span class="token operator">:</span><span class="token string">&quot;FieldsV1&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;fieldsV1&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token property">&quot;f:metadata&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token property">&quot;f:labels&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token property">&quot;.&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token property">&quot;f:kubernetes.io/metadata.name&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">}</span><span class="token punctuation">}</span><span class="token punctuation">}</span><span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token property">&quot;spec&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token property">&quot;finalizers&quot;</span><span class="token operator">:</span><span class="token punctuation">[</span><span class="token string">&quot;kubernetes&quot;</span><span class="token punctuation">]</span><span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token property">&quot;status&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token property">&quot;phase&quot;</span><span class="token operator">:</span><span class="token string">&quot;Active&quot;</span><span class="token punctuation">}</span><span class="token punctuation">}</span>\n</code></pre></div>',25);t.render=function(a,e,t,p,c,l){return s(),n("div",null,[o])};export default t;export{e as __pageData};
